class Solution:
    def maximumStrength(self, nums, k):
        # Brute-force only correct for small n and small k
        # Uses the same two-step DP but iterates naively O(n*k)
        n = len(nums)
        NEG_INF = float('-inf')
        closed = [NEG_INF] * (k + 1)
        opened = [NEG_INF] * (k + 1)
        closed[0] = 0
        for x in nums:
            # Close open groups first (between elements)
            for j in range(1, k + 1):
                if opened[j] != NEG_INF:
                    closed[j] = max(closed[j], opened[j])
            new_opened = opened[:]
            for j in range(1, k + 1):
                sign = 1 if j % 2 == 1 else -1
                weight = (k + 1 - j) * sign * x
                if closed[j - 1] != NEG_INF:
                    new_opened[j] = max(new_opened[j], closed[j - 1] + weight)
                if opened[j] != NEG_INF:
                    new_opened[j] = max(new_opened[j], opened[j] + weight)
            opened = new_opened
        for j in range(1, k + 1):
            if opened[j] != NEG_INF:
                closed[j] = max(closed[j], opened[j])
        return closed[k]

