            for j in range(1, k + 1):
                if opened[j] != NEG_INF:
                    closed[j] = max(closed[j], opened[j])
            # Step 2: incorporate current element
            new_opened = opened[:]
            for j in range(1, k + 1):
                sign = 1 if j % 2 == 1 else -1
                weight = (k + 1 - j) * sign * x
                if closed[j - 1] != NEG_INF:
                    new_opened[j] = max(new_opened[j], closed[j - 1] + weight)
                if opened[j] != NEG_INF:
                    new_opened[j] = max(new_opened[j], opened[j] + weight)
            opened = new_opened
        # Close any remaining open group at the end
        for j in range(1, k + 1):
            if opened[j] != NEG_INF:
                closed[j] = max(closed[j], opened[j])
        return closed[k]

