var maximumStrength = function(nums, k) {
    const NEG_INF = -Infinity;
    const closed = new Array(k + 1).fill(NEG_INF);
    const opened = new Array(k + 1).fill(NEG_INF);
    closed[0] = 0;
    for (const x of nums) {
        // Step 1: close any open group
        for (let j = 1; j <= k; j++) {
            if (opened[j] !== NEG_INF)
                closed[j] = Math.max(closed[j], opened[j]);
        }
        // Step 2: incorporate current element
        const newOpened = opened.slice();
        for (let j = 1; j <= k; j++) {
            const sign = j % 2 === 1 ? 1 : -1;
            const weight = (k + 1 - j) * sign * x;
            if (closed[j - 1] !== NEG_INF)
                newOpened[j] = Math.max(newOpened[j], closed[j - 1] + weight);
            if (opened[j] !== NEG_INF)
                newOpened[j] = Math.max(newOpened[j], opened[j] + weight);
        }
        for (let j = 0; j <= k; j++) opened[j] = newOpened[j];
    }
    // Close remaining open groups
    for (let j = 1; j <= k; j++) {
        if (opened[j] !== NEG_INF)
            closed[j] = Math.max(closed[j], opened[j]);
    }
    return closed[k];
};
